def validate_redirect_uri(redirect_uri, allowed_domains):
    """
    Validate redirect URI against allowed domains with exact matching.
    Prevents open redirect vulnerabilities.
    """
    if not redirect_uri:
        return False
    
    try:
        parsed = urlparse(redirect_uri)
        
        # Ensure HTTPS for security
        if parsed.scheme != 'https':
            return False
        
        # Extract hostname
        hostname = parsed.hostname
        if not hostname:
            return False
        
        # Exact domain matching or proper subdomain validation
        for domain in allowed_domains:
            # Check if hostname equals domain or is a proper subdomain
            if hostname == domain or hostname.endswith('.' + domain):
                return True
        
        return False
    except Exception:
        return False

