@app.route('/oauth/callback')
def oauth_callback():
    """
    Handle OAuth 2.0 callback with security validations
    """
    # Validate state parameter (CSRF protection)
    state = request.args.get('state')
    if not state or state != session.get('oauth_state'):
        return jsonify({'error': 'invalid_state', 'message': 'State validation failed'}), 400
    
