@app.route('/oauth/refresh')
def oauth_refresh():
    """
    Refresh access token using refresh token
    """
    refresh_token = session.get('refresh_token')
    
    if not refresh_token:
        return jsonify({'error': 'no_refresh_token', 'message': 'No refresh token available'}), 400
    
    token_params = {
        'grant_type': 'refresh_token',
        'refresh_token': refresh_token,
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret']
    }
    
    try:
        token_response = requests.post(
            OAUTH_CONFIG['token_endpoint'],
            data=token_params,
            headers={'Accept': 'application/json'},
            timeout=10
        )
        
        if token_response.status_code != 200:
            return jsonify({'error': 'refresh_failed', 'message': 'Token refresh failed'}), 400
        
        token_data = token_response.json()
        
        # Update session with new tokens
        session['access_token'] = token_data.get('access_token')
        if 'refresh_token' in token_data:
            session['refresh_token'] = token_data.get('refresh_token')
        
        return jsonify({'message': 'Token refreshed successfully', 'token_data': token_data})
        
    except requests.RequestException:
        return jsonify({'error': 'network_error', 'message': 'Failed to refresh token'}), 500

